import React, { useEffect, useState } from "react";
import { io } from "socket.io-client";
import waveIcon from "../assets/waveAgent.png";
import "./chatBot.css";

const socket = io("http://localhost:3002");

const ChatBot = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    socket.on("aiMessage", (msg) => {
      setMessages((prev) => [...prev, { type: "ai", text: msg }]);
    });

    return () => {
      socket.off("aiMessage");
    };
  }, []);

  const sendMessage = () => {
    if (!input.trim()) return;

    socket.emit("userMessage", input);
    setMessages((prev) => [...prev, { type: "user", text: input }]);
    setInput("");
  };

  return (
    <>
      {/* Floating Agent Icon */}
      {!isOpen && (
        <img
          src={waveIcon}
          alt="Wave Agent"
          className="chat-icon-img"
          onClick={() => setIsOpen(true)}
        />
      )}

      {/* Chat Window */}
      {isOpen && (
        <div className="chat-window">
          {/* Header */}
          <div className="chat-window-header">
            <button
              className="back-btn"
              onClick={() => setIsOpen(false)}
            >
              ←
            </button>
            <span className="chat-title">Wave Agent</span>
          </div>

          {/* Messages */}
          <div className="chat-body">
            {messages.map((msg, i) => (
              <div key={i} className={`msg ${msg.type}`}>
                {msg.text}
              </div>
            ))}
          </div>

          {/* Input */}
          <div className="chat-input">
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder="Ask about portfolio or buy stock..."
              onKeyDown={(e) => e.key === "Enter" && sendMessage()}
            />
            <button onClick={sendMessage}>Send</button>
          </div>
        </div>
      )}
    </>
  );
};

export default ChatBot;
